INSERT OR IGNORE INTO Articles (text, category_id) VALUES (': DL n.º 480/99, de 09 de Novembro   
     
                         
                          
  Artigo 94.º Sustação da execução com penhora anterior
                            
                           
                             
                               
                             
     (Revogado pelo Decreto-Lei n.º 295/2009, de 13/10).            
         
